def unique_digits(x):
    """Given a list of positive integers x. return a sorted list of all 
    elements that hasn't any even digit.

    Note: Returned list should be sorted in increasing order.

    For example:
    >>> unique_digits([15, 33, 1422, 1])
    [1, 15, 33]
    >>> unique_digits([152, 323, 1422, 10])
    []
    """
    def has_no_even_digit(n):
        return all(int(d) % 2 != 0 for d in str(n))

    return sorted(num for num in x if has_no_even_digit(num))

def by_length(arr):
    names = {
        1: "One", 2: "Two", 3: "Three", 4: "Four", 5: "Five",
        6: "Six", 7: "Seven", 8: "Eight", 9: "Nine"
    }
    filtered = sorted([x for x in arr if 1 <= x <= 9], reverse=True)
    return [names[x] for x in filtered]

def order_by_points(nums):
    def digit_sum(n):
        s = str(n)
        if s[0] == '-':
            # For negative numbers, the first digit after '-' is negated
            digits = [int(d) for d in s[1:]]
            digits[0] = -digits[0]
            return sum(digits)
        else:
            return sum(int(d) for d in s)

    return sorted(nums, key=lambda x: digit_sum(x))

def tri(n):
    if n == 0:
        return [1]

    results = [0] * (n + 1)
    results[0] = 1
    results[1] = 3

    for i in range(2, n + 1):
        if i % 2 == 0:
            results[i] = 1 + i / 2
        else:
            # tri(n) = tri(n-1) + tri(n-2) + tri(n+1)
            # tri(n+1) = 1 + (n+1)/2 since n is odd means n+1 is even
            results[i] = results[i - 1] + results[i - 2] + (1 + (i + 1) / 2)

    return results

def sort_array(array):
    if not array:
        return []
    total = array[0] + array[-1]
    if total % 2 == 1:
        return sorted(array)
    else:
        return sorted(array, reverse=True)

def compare_one(a, b):
    """
    Create a function that takes integers, floats, or strings representing
    real numbers, and returns the larger variable in its given variable type.
    Return None if the values are equal.
    Note: If a real number is represented as a string, the floating point might be . or ,

    compare_one(1, 2.5) ➞ 2.5
    compare_one(1, "2,3") ➞ "2,3"
    compare_one("5,1", "6") ➞ "6"
    compare_one("1", 1) ➞ None
    """
    def to_float(x):
        if isinstance(x, str):
            return float(x.replace(',', '.'))
        return float(x)

    fa = to_float(a)
    fb = to_float(b)

    if fa == fb:
        return None
    elif fa > fb:
        return a
    else:
        return b
